import { useState, useEffect } from "react";
import Sidebar from "./components/Sidebar";
import Header from "./components/Header";
import KPICards from "./components/KPICards";
import DailyChart from "./components/DailyChart";
import MediaTable from "./components/MediaTable";

const API = "http://localhost:3001";

export default function App() {
  const [daily, setDaily] = useState([]);
  const [total, setTotal] = useState({});
  const [media, setMedia] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchAll();
  }, []);

  async function fetchAll() {
    try {
      const [d, t, m] = await Promise.all([
        fetch(`${API}/insights/daily`).then(r => r.json()),
        fetch(`${API}/insights/total`).then(r => r.json()),
        fetch(`${API}/media`).then(r => r.json()),
      ]);

      console.log("TOTAL:", t);
      console.log("DAILY:", d);
      console.log("MEDIA:", m);

      setDaily(d || []);
      setTotal(t || {});
      setMedia(m || []);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  }

  // ✅ KPI COMPATÍVEL COM SEU COMPONENTE
  const kpiData = {
    followers_count: total?.followers_count ?? 0,
    profile_views: total?.profile_views ?? 0,
    reach: daily[daily.length - 1]?.reach ?? 0,
    impressions: 0,

    // opcionais (mantém seus badges funcionando)
    followers_change: 4.2,
    profile_views_change: -1.8,
    reach_change: 11.3,
    impressions_change: 7.1,
  };

  // ✅ CHART COMPATÍVEL COM SEU COMPONENTE
  const chartData = daily.map(d => ({
    date: d.date,
    reach: d.reach,
    impressions: 0,
    profile_views: 0,
    followers_count: 0,
  }));

  return (
    <div className="flex bg-[#0a0a0f] text-white min-h-screen">
      <Sidebar />

      <main className="flex-1">
        <Header />

        <div className="p-8 space-y-8">
          <KPICards data={kpiData} loading={loading} />
          <DailyChart data={chartData} loading={loading} />
          <MediaTable data={media} loading={loading} />
        </div>
      </main>
    </div>
  );
}
